const ExcelJS = require('exceljs');
return await (async () => {
  const jst = new Date(new Date().getTime() + 9 * 3600000);
  const year = jst.getFullYear(), month = jst.getMonth() + 1, day = jst.getDate();
  const lineToken = 'Bearer YOUR_EXPENSE_LINE_TOKEN';
  const userIds = ['YOUR_USERID_NOZOE_YU', 'YOUR_USERID_NOZOE_AKIKO'];
  const fmt = n => (n||0).toLocaleString('ja-JP');
  const getV = c => (c&&typeof c==='object'&&'result'in c)?c.result:c;
  const dStr = d => { if(!(d instanceof Date))return String(d||''); return `${d.getFullYear()}/${String(d.getMonth()+1).padStart(2,'0')}/${String(d.getDate()).padStart(2,'0')}`; };
  const addM = (y,m,n) => { const d=new Date(Date.UTC(y,m-1+n,1)); return {year:d.getFullYear(),month:d.getMonth()+1}; };

  const sendPush = async (text) => {
    for (const uid of userIds) {
      if (uid.startsWith('YOUR_')) continue;
      await this.helpers.httpRequest({
        method:'POST', url:'https://api.line.me/v2/bot/message/push',
        headers:{'Authorization':lineToken},
        body:{to:uid, messages:[{type:'text',text}]}, json:true
      });
    }
  };

  const creds = await this.getCredentials('microsoftDriveOAuth2Api');
  const msToken = creds.oauthTokenData?.access_token;
  if (!msToken) return [{ json:{error:'MS token missing'} }];

  const loadWb = async (path) => {
    try {
      const info = await this.helpers.httpRequest({
        method:'GET', url:`https://graph.microsoft.com/v1.0/me/drive/root:${path}`,
        headers:{'Authorization':`Bearer ${msToken}`}, json:true
      });
      const dl = info['@microsoft.graph.downloadUrl'];
      if (!dl) return null;
      const res = await this.helpers.httpRequest({method:'GET',url:dl,encoding:'arraybuffer',returnFullResponse:false});
      const wb = new ExcelJS.Workbook();
      await wb.xlsx.load(Buffer.from(res),{useSharedStrings:false});
      return wb;
    } catch(e) { return null; }
  };

  const prev1 = addM(year,month,-1), prev2 = addM(year,month,-2);
  const basePath = '/業務管理システム/経費管理/月次/';
  const [curWb, p1Wb, p2Wb] = await Promise.all([
    loadWb(`${basePath}経営管理_${year}年${month}月.xlsx`),
    loadWb(`${basePath}経営管理_${prev1.year}年${prev1.month}月.xlsx`),
    loadWb(`${basePath}経営管理_${prev2.year}年${prev2.month}月.xlsx`)
  ]);

  const today = new Date(Date.UTC(year,month-1,day));
  const alerts = [];

  // ===【毎日】入金遅延チェック ===
  const overdueRecv = [];
  const seenRecv = new Set();
  for (const wb of [curWb,p1Wb,p2Wb]) {
    if (!wb) continue;
    const ws = wb.getWorksheet('売上管理');
    if (!ws) continue;
    ws.eachRow((row,n) => {
      if(n<2)return;
      const c=getV(row.getCell(3).value), st=getV(row.getCell(12).value);
      const due=getV(row.getCell(9).value), amt=Number(getV(row.getCell(7).value))||0;
      const key=`${c}_${dStr(due)}`;
      if(c&&st==='未入金'&&due instanceof Date&&due<today&&!seenRecv.has(key)){
        seenRecv.add(key);
        const days=Math.floor((today-due)/86400000);
        overdueRecv.push(`${c}\n  ¥${fmt(amt)}  期限:${dStr(due)}（${days}日超過）`);
      }
    });
  }
  if (overdueRecv.length) alerts.push(`⚠ 入金遅延があります\n\n${overdueRecv.join('\n\n')}\n\n計${overdueRecv.length}件`);

  // ===【毎日】振込遅延チェック ===
  const overduePaym = [];
  const seenPaym = new Set();
  for (const wb of [curWb,p1Wb,p2Wb]) {
    if (!wb) continue;
    const ws = wb.getWorksheet('外注管理');
    if (!ws) continue;
    ws.eachRow((row,n) => {
      if(n<2)return;
      const v=getV(row.getCell(3).value), st=getV(row.getCell(14).value);
      const due=getV(row.getCell(11).value), amt=Number(getV(row.getCell(9).value))||0;
      const key=`${v}_${dStr(due)}`;
      if(v&&st==='未払'&&due instanceof Date&&due<today&&!seenPaym.has(key)){
        seenPaym.add(key);
        const days=Math.floor((today-due)/86400000);
        overduePaym.push(`${v}\n  ¥${fmt(amt)}  期限:${dStr(due)}（${days}日超過）`);
      }
    });
  }
  if (overduePaym.length) alerts.push(`⚠ 振込遅延があります\n\n${overduePaym.join('\n\n')}\n\n計${overduePaym.length}件`);

  // ===【毎月3日】売上未入金確認（前月分）===
  if (day === 3) {
    const ws = p1Wb && p1Wb.getWorksheet('売上管理');
    const list = [];
    if (ws) ws.eachRow((row,n) => {
      if(n<2)return;
      const c=getV(row.getCell(3).value), st=getV(row.getCell(12).value);
      const amt=Number(getV(row.getCell(7).value))||0, due=getV(row.getCell(9).value);
      if(c&&st==='未入金') list.push(`${c}\n  ¥${fmt(amt)}  期限:${dStr(due)}`);
    });
    alerts.push(list.length
      ? `【売上未入金確認】\n前月分（${prev1.year}年${prev1.month}月）\n\n${list.join('\n\n')}\n\n計${list.length}件`
      : `【売上未入金確認】\n前月分の未入金はありません ✅`);
  }

  // ===【毎月8日】給与・秀電工支払リマインダー ===
  if (day === 8) {
    alerts.push(`【支払リマインダー】\n\n明後日（10日）が支払日です\n\n■ 従業員給与\n  丸田翔吾・源地健史\n\n■ 秀電工（服部秀一）\n  外注管理の未払いを確認してください\n\n支払期限が近い外注の確認もお願いします。`);
  }

  // ===【毎月11日】外注請求書未着チェック（翌月末払い業者）===
  if (day === 11) {
    const SUBCONS = ['井本貴史','梶原通信','LLS電気','株式会社トラストテクノス','株式会社RISE'];
    const katsuWb = await loadWb(`/業務管理システム/日報/稼働表_${prev1.year}年${prev1.month}月.xlsx`);
    const activeVendors = [];
    if (katsuWb) {
      for (const v of SUBCONS) {
        const ws = katsuWb.getWorksheet(v);
        let active = false;
        if (ws) ws.eachRow((r,n) => { if(n>=2&&getV(r.getCell(1).value))active=true; });
        if (active) activeVendors.push(v);
      }
    }
    const thisMonthEnd = new Date(Date.UTC(year,month,0));
    const missing = [];
    for (const v of activeVendors) {
      let found = false;
      for (const wb of [curWb,p1Wb]) {
        if (!wb||found) continue;
        const ws = wb.getWorksheet('外注管理');
        if (!ws) continue;
        ws.eachRow((row,n) => {
          if(n<2||found)return;
          const vn=getV(row.getCell(3).value), due=getV(row.getCell(11).value);
          if(vn===v&&due instanceof Date&&due.getFullYear()===thisMonthEnd.getFullYear()&&due.getMonth()===thisMonthEnd.getMonth()) found=true;
        });
      }
      if (!found) missing.push(v);
    }
    if (missing.length) alerts.push(`【外注請求書未着】\n以下の業者から今月の請求書が届いていません\n\n${missing.map(v=>`⚠ ${v}`).join('\n')}\n\n支払期限：${year}年${month}月末`);
  }

  // ===【毎月15日】オークコミュニケーション未入金確認 ===
  if (day === 15) {
    const oakList = [];
    const seenOak = new Set();
    for (const wb of [curWb,p1Wb,p2Wb]) {
      if (!wb) continue;
      const ws = wb.getWorksheet('売上管理');
      if (!ws) continue;
      ws.eachRow((row,n) => {
        if(n<2)return;
        const c=getV(row.getCell(3).value), st=getV(row.getCell(12).value);
        const amt=Number(getV(row.getCell(7).value))||0, due=getV(row.getCell(9).value);
        const key=`${dStr(due)}_${amt}`;
        if(c==='オークコミュニケーション'&&st==='未入金'&&!seenOak.has(key)){
          seenOak.add(key); oakList.push(`¥${fmt(amt)}  期限:${dStr(due)}`);
        }
      });
    }
    alerts.push(oakList.length
      ? `【オークコミュニケーション 未入金確認】\n\n${oakList.join('\n')}`
      : `【オークコミュニケーション 未入金確認】\n✅ 未入金はありません`);
  }

  // ===【毎月21日】秀電工請求書未着チェック ===
  if (day === 21) {
    const katsuWb = await loadWb(`/業務管理システム/日報/稼働表_${prev1.year}年${prev1.month}月.xlsx`);
    let hideoActive = false;
    if (katsuWb) {
      const ws = katsuWb.getWorksheet('服部秀一');
      if (ws) ws.eachRow((r,n) => { if(n>=2&&getV(r.getCell(1).value))hideoActive=true; });
    }
    if (hideoActive) {
      const payM = addM(prev1.year,prev1.month,2);
      const expDue = new Date(Date.UTC(payM.year,payM.month-1,10));
      let found = false;
      for (const wb of [curWb,p1Wb]) {
        if (!wb||found) continue;
        const ws = wb.getWorksheet('外注管理');
        if (!ws) continue;
        ws.eachRow((row,n) => {
          if(n<2||found)return;
          const v=getV(row.getCell(3).value), due=getV(row.getCell(11).value);
          if(v==='秀電工'&&due instanceof Date&&due.getFullYear()===expDue.getFullYear()&&due.getMonth()===expDue.getMonth()&&due.getDate()===10) found=true;
        });
      }
      if (!found) alerts.push(`【秀電工 請求書未着】\n秀電工（服部秀一）の請求書がまだ届いていません\n\n支払期限：${payM.year}年${payM.month}月10日`);
    }
  }

  // ===【毎月25日】外注未払い確認 ===
  if (day === 25) {
    const unpaid = [];
    const seenUp = new Set();
    for (const wb of [curWb,p1Wb]) {
      if (!wb) continue;
      const ws = wb.getWorksheet('外注管理');
      if (!ws) continue;
      ws.eachRow((row,n) => {
        if(n<2)return;
        const v=getV(row.getCell(3).value), st=getV(row.getCell(14).value);
        const amt=Number(getV(row.getCell(9).value))||0, due=getV(row.getCell(11).value);
        const key=`${v}_${dStr(due)}`;
        if(v&&st==='未払'&&!seenUp.has(key)){ seenUp.add(key); unpaid.push(`${v}\n  ¥${fmt(amt)}  期限:${dStr(due)}`); }
      });
    }
    alerts.push(unpaid.length
      ? `【外注未払い確認】\n来月の支払いに向けて確認してください\n\n${unpaid.join('\n\n')}\n\n計${unpaid.length}件`
      : `【外注未払い確認】\n✅ 未払いはありません`);
  }

  for (const alert of alerts) { await sendPush(alert); }
  return [{ json:{ date:`${year}/${month}/${day}`, alertCount:alerts.length } }];
})();
